Here's how to implement all three requirements:

## 1. Custom "Cancel" Back Button (EditProductPage.xaml)

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             x:Class="MyApp.Views.EditProductPage">

    <Shell.BackButtonBehavior>
        <BackButtonBehavior TextOverride="Cancel"
                           Command="{Binding CancelCommand}" />
    </Shell.BackButtonBehavior>

    <!-- page content -->
</ContentPage>
```

## 2. Navigation Guard in AppShell.xaml.cs

Use `OnNavigating` with `GetDeferral()` to intercept back navigation and show a confirmation dialog:

```csharp
public partial class AppShell : Shell
{
    public AppShell()
    {
        InitializeComponent();
        Routing.RegisterRoute("editproduct", typeof(EditProductPage));
    }

    protected override async void OnNavigating(ShellNavigatingEventArgs args)
    {
        base.OnNavigating(args);

        // Only intercept back (Pop) navigation from EditProductPage
        if (args.Source == ShellNavigationSource.Pop &&
            CurrentPage is EditProductPage editPage &&
            editPage.BindingContext is EditProductViewModel vm &&
            vm.HasUnsavedChanges)
        {
            var deferral = args.GetDeferral();

            bool discard = await CurrentPage.DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard them?",
                "Discard", "Stay");

            if (!discard)
                args.Cancel();   // user chose "Stay" — cancel navigation

            deferral.Complete();
        }
    }
}
```

## 3. ViewModel with CancelCommand

```csharp
public partial class EditProductViewModel : ObservableObject
{
    [ObservableProperty]
    private bool hasUnsavedChanges;

    [RelayCommand]
    private async Task Cancel()
    {
        if (HasUnsavedChanges)
        {
            bool discard = await Shell.Current.CurrentPage.DisplayAlert(
                "Unsaved Changes",
                "You have unsaved changes. Discard them?",
                "Discard", "Stay");

            if (!discard)
                return;
        }

        await Shell.Current.GoToAsync("..");
    }
}
```

**Key points:**
- `GetDeferral()` is required because `DisplayAlert` is async — without it, navigation completes before the dialog returns.
- The `OnNavigating` guard handles the system back gesture/button; the `CancelCommand` handles your custom "Cancel" button tap.
- Both paths share the same confirmation logic, so the user can't bypass the check.
